(()=>{
  window.__gomokuTC = (() => {
    const controlsRe = /undo|restart|reset|new game|play again|start|hint|悔棋|撤销|重新|新局/i;
    const visible = (el) => {
      if (!el || !el.getBoundingClientRect) return false;
      const r = el.getBoundingClientRect();
      const s = getComputedStyle(el);
      return r.width > 4 && r.height > 4 && s.display !== 'none' && s.visibility !== 'hidden' && r.bottom > 0 && r.right > 0;
    };
    const bodyText = () => (document.body.innerText || document.body.textContent || '').replace(/\s+/g, ' ').trim();
    const unique = (arr) => Array.from(new Set(arr));
    const sortGrid = (arr) => arr.slice().sort((a,b) => {
      const ra = a.getBoundingClientRect();
      const rb = b.getBoundingClientRect();
      if (Math.abs(ra.top - rb.top) > Math.max(3, Math.min(ra.height, rb.height) * 0.45)) return ra.top - rb.top;
      return ra.left - rb.left;
    });
    function candidateCells() {
      const direct = Array.from(document.querySelectorAll('td,.cell,.intersection,.point,.grid-cell,.board-cell,[data-row][data-col],[data-x][data-y],[data-index],button'))
        .filter(el => visible(el) && !(el.matches('button') && controlsRe.test(el.textContent || '')));
      let cells = direct;
      if (cells.length < 225) {
        for (const root of Array.from(document.querySelectorAll('*')).filter(visible)) {
          const label = ((root.id || '') + ' ' + (root.className || '')).toLowerCase();
          const kids = Array.from(root.children || []).filter(el => visible(el) && !controlsRe.test(el.textContent || ''));
          if (kids.length >= 200 && (/board|grid|gomoku|game/.test(label) || kids.length <= 260)) cells = cells.concat(kids);
        }
      }
      return sortGrid(unique(cells)).slice(0, 225);
    }
    function canvasEl() {
      return Array.from(document.querySelectorAll('canvas')).filter(visible).sort((a,b) => {
        const ra = a.getBoundingClientRect(), rb = b.getBoundingClientRect();
        return rb.width * rb.height - ra.width * ra.height;
      })[0] || null;
    }
    function canvasData() {
      const c = canvasEl();
      if (!c) return '';
      try { return c.toDataURL(); } catch (e) { return ''; }
    }
    function numericPieceCount() {
      const t = bodyText();
      const patterns = [
        /(?:pieces?|stones?|moves?|placed|count)\D{0,20}(\d+)/i,
        /(\d+)\D{0,20}(?:pieces?|stones?|moves?|placed)/i
      ];
      for (const p of patterns) {
        const m = t.match(p);
        if (m) return Number(m[1]);
      }
      return null;
    }
    function domStoneCount() {
      const cells = candidateCells();
      let count = 0;
      for (const cell of cells) {
        const marker = ((cell.className || '') + ' ' + (cell.innerHTML || '') + ' ' + (cell.textContent || '')).toLowerCase();
        if (/piece|stone|black|white|occupied|placed|winner|winning|●|○|⚫|⚪/.test(marker) || cell.children.length > 0) count++;
      }
      return count;
    }
    function placedCount() {
      const n = numericPieceCount();
      return Math.max(domStoneCount(), Number.isFinite(n) ? n : 0);
    }
    function hasBlackWhiteEvidence() {
      const cells = candidateCells();
      let black = false, white = false;
      for (const cell of cells) {
        const marker = ((cell.className || '') + ' ' + (cell.innerHTML || '') + ' ' + (cell.textContent || '')).toLowerCase();
        black = black || /black|black-piece|blackstone|●|⚫/.test(marker);
        white = white || /white|white-piece|whitestone|○|⚪/.test(marker);
      }
      const t = bodyText().toLowerCase();
      return (black && white) || (/white/.test(t) && /black/.test(t));
    }
    function fireAt(x, y) {
      const el = document.elementFromPoint(x, y) || canvasEl() || document.body;
      for (const type of ['pointerdown','mousedown','pointerup','mouseup','click']) {
        el.dispatchEvent(new MouseEvent(type, {bubbles:true, cancelable:true, clientX:x, clientY:y, button:0}));
      }
      return true;
    }
    function clickAt(row, col) {
      const cells = candidateCells();
      if (cells.length >= 225) {
        const cell = cells[Math.max(0, Math.min(224, row * 15 + col))];
        const r = cell.getBoundingClientRect();
        return fireAt(r.left + r.width / 2, r.top + r.height / 2);
      }
      const c = canvasEl();
      if (c) {
        const r = c.getBoundingClientRect();
        return fireAt(r.left + (col + 0.5) * r.width / 15, r.top + (row + 0.5) * r.height / 15);
      }
      return false;
    }
    function clickMoves(moves) {
      let ok = true;
      for (const [r,c] of moves) ok = clickAt(r,c) && ok;
      return ok;
    }
    function clickControl(re) {
      const controls = Array.from(document.querySelectorAll('button,a,input[type=button],input[type=submit]')).filter(visible);
      const target = controls.find(el => re.test((el.textContent || el.value || el.getAttribute('aria-label') || el.title || '')));
      if (!target) return false;
      const r = target.getBoundingClientRect();
      return fireAt(r.left + r.width / 2, r.top + r.height / 2);
    }
    const snapshots = {};
    function snapshot(name) {
      snapshots[name] = {text: bodyText(), canvas: canvasData(), stones: domStoneCount(), count: numericPieceCount(), placed: placedCount()};
      return true;
    }
    function changedFrom(name) {
      const s = snapshots[name] || {};
      const nowText = bodyText();
      const nowCanvas = canvasData();
      const nowCount = numericPieceCount();
      return domStoneCount() > (s.stones || 0)
        || (Number.isFinite(nowCount) && Number.isFinite(s.count) && nowCount > s.count)
        || placedCount() > (s.placed || 0)
        || (nowCanvas && s.canvas && nowCanvas !== s.canvas)
        || (nowText !== s.text && /black|white|turn|piece|stone|move|placed|win|\b[1-9]\b/i.test(nowText));
    }
    function turnAfterTwoMovesOk() {
      const t1 = snapshots.afterFirst?.text || '';
      const t2 = bodyText();
      const whiteAfterFirst = /white/i.test(t1) || /white/i.test(t2);
      const blackAfterSecond = /black/i.test(t2);
      return hasBlackWhiteEvidence() || (whiteAfterFirst && blackAfterSecond && placedCount() >= 2);
    }
    function undoOk() {
      const afterTwo = snapshots.afterTwo || {};
      const n = numericPieceCount();
      return Boolean((Number.isFinite(n) && n <= 1)
        || domStoneCount() < (afterTwo.stones || 2)
        || (canvasData() && afterTwo.canvas && canvasData() !== afterTwo.canvas && /white|turn/i.test(bodyText())));
    }
    function restartOk() {
      const n = numericPieceCount();
      return (Number.isFinite(n) && n === 0)
        || placedCount() === 0
        || (/black/i.test(bodyText()) && /\b0\b/.test(bodyText()));
    }
    function winOk() {
      const t = bodyText();
      const hasWinText = /black[^.]{0,40}(wins?|won)|winner|game over|five in a row|胜/i.test(t);
      const highlighted = Array.from(document.querySelectorAll('*')).filter(el => {
        if (!visible(el)) return false;
        const marker = ((el.className || '') + ' ' + (el.id || '') + ' ' + (el.getAttribute('style') || '')).toLowerCase();
        return /win|winner|winning|highlight|gold|yellow|selected/.test(marker);
      }).length >= 5;
      return hasWinText || highlighted;
    }
    return {visible, bodyText, candidateCells, canvasEl, numericPieceCount, domStoneCount, placedCount, hasBlackWhiteEvidence, snapshot, clickAt, clickMoves, clickControl, changedFrom, turnAfterTwoMovesOk, undoOk, restartOk, winOk};
  })();
  window.__gomokuTC.snapshot('initial');
  return true;
})()

